class Solution:
    def rightSideView(self, root):
        seen = {}
        def walk(node, depth):
            if node is None:
                return
            seen[depth] = node.val
            walk(node.left, depth + 1)
            walk(node.right, depth + 1)
        walk(root, 0)
        return [seen[d] for d in range(len(seen))]

