var rightSideView = function(root) {
    if (!root) return [];
    const res = [];
    let level = [root];
    while (level.length) {
        res.push(level[level.length - 1].val);
        const next = [];
        for (const node of level) {
            if (node.left) next.push(node.left);
            if (node.right) next.push(node.right);
        }
        level = next;
    }
    return res;
};
